#!/usr/bin/env node
/**
 * code_boss — single-file bundle. Generated by scripts/build.mjs; do not edit
 * the body. Edit the CONFIG constants below for your environment.
 *
 *   LLM_MODE='openai-http'           production: hits BASE_URL with API_KEY
 *   LLM_MODE='claude-code-headless'  local dev: requires @anthropic-ai/claude-agent-sdk installed
 *
 * Usage:
 *   node code-boss.mjs "What is the capital of Japan?"
 *   AGENT_STREAM=1 node code-boss.mjs "Name three primary colors."
 */

// ====== CONFIG (edit these) ======
const LLM_MODE  = 'claude-code-headless';            // 'claude-code-headless' | 'openai-http'
const API_KEY   = '';                                // bearer token for openai-http
const BASE_URL  = 'https://api.genai.mil/v1';        // production endpoint
const MODEL     = LLM_MODE === 'openai-http'
  ? 'gemini-pro'
  : 'claude-opus-4-7';
// ==================================

import { randomUUID } from 'node:crypto';

// SDK loaded lazily — only when LLM_MODE === 'claude-code-headless'.
let query;


// ====== llm/openai-http.mjs ======
/**
 * Production OpenAI-compatible HTTP adapter — talks to api.genai.mil.
 *
 * Same surface as the dev adapter:
 *   const a = createHttpAdapter({ baseURL, apiKey })
 *   await a.complete(openaiRequest)
 *   for await (const chunk of a.completeStream(openaiRequest)) { ... }
 *
 * Production behaviours wired in here:
 *   - 401 with `unlock_url` → GET the unlock URL, retry once
 *   - 429 with Retry-After header or retry_after_seconds body → sleep, retry
 *     (max 3 attempts, exponential floor)
 *   - SSE streaming parsed into OpenAI ChatCompletionChunk async iterator
 *   - Bearer auth via Authorization header
 *
 * No npm deps. Node 18+ built-in fetch only.
 */

const DEFAULT_BASE_URL = 'https://api.genai.mil/v1';

class HttpError extends Error {
  constructor(status, statusText, body) {
    super(`HTTP ${status} ${statusText}: ${typeof body === 'string' ? body.slice(0, 500) : JSON.stringify(body).slice(0, 500)}`);
    this.status = status;
    this.statusText = statusText;
    this.body = body;
  }
}

function sleep(ms) {
  return new Promise((r) => setTimeout(r, ms));
}

function parseRetryAfter(headers, body) {
  const headerVal = headers.get?.('retry-after');
  const headerSec = headerVal ? Number(headerVal) : NaN;
  const bodySec = Number(body?.retry_after_seconds);
  const candidates = [headerSec, bodySec].filter((n) => Number.isFinite(n) && n > 0);
  if (candidates.length === 0) return 1;
  return Math.max(...candidates);
}

async function readJson(res) {
  const text = await res.text();
  try {
    return JSON.parse(text);
  } catch {
    return { raw: text };
  }
}

/**
 * @param {object} opts
 * @param {string} [opts.baseURL]     Defaults to https://api.genai.mil/v1
 * @param {string} [opts.apiKey]      Bearer token. Defaults to process.env.AGENT_API_KEY.
 * @param {Function} [opts.fetchImpl] Override for tests (default: globalThis.fetch).
 * @param {number}   [opts.maxRetries] Default 3.
 * @param {Function} [opts.onUnlock]   Callback(url) when an unlock is performed (telemetry).
 * @param {Function} [opts.onRateLimit] Callback(ms) when a 429 sleep happens (telemetry).
 * @param {Function} [opts.onUsage]    Callback(usage) on successful response.
 */
function createHttpAdapter(opts = {}) {
  const baseURL = (opts.baseURL ?? process.env.AGENT_BASE_URL ?? DEFAULT_BASE_URL).replace(/\/+$/, '');
  const apiKey = opts.apiKey ?? process.env.AGENT_API_KEY ?? '';
  const fetchImpl = opts.fetchImpl ?? globalThis.fetch;
  const maxRetries = opts.maxRetries ?? 3;
  const onUnlock = opts.onUnlock ?? (() => {});
  const onRateLimit = opts.onRateLimit ?? (() => {});
  const onUsage = opts.onUsage ?? (() => {});

  if (!fetchImpl) throw new Error('createHttpAdapter: no fetch implementation available');

  async function doFetchOnce(path, init) {
    const url = `${baseURL}${path}`;
    const headers = {
      'content-type': 'application/json',
      accept: init?.body && JSON.parse(init.body).stream ? 'text/event-stream' : 'application/json',
      ...(apiKey ? { authorization: `Bearer ${apiKey}` } : {}),
      ...(init?.headers ?? {}),
    };
    return fetchImpl(url, { ...init, headers });
  }

  async function safeFetch(path, init) {
    let attempt = 0;
    let unlocked = false;
    while (true) {
      const res = await doFetchOnce(path, init);
      if (res.ok) return res;

      if (res.status === 401 && !unlocked) {
        const body = await readJson(res);
        const unlockUrl = body?.unlock_url ?? body?.error?.unlock_url;
        if (unlockUrl) {
          onUnlock(unlockUrl);
          const u = await fetchImpl(unlockUrl);
          if (!u.ok) throw new HttpError(u.status, u.statusText, await readJson(u));
          unlocked = true;
          continue;
        }
        throw new HttpError(res.status, res.statusText, body);
      }

      if (res.status === 429 && attempt < maxRetries) {
        const body = await readJson(res);
        const waitSec = parseRetryAfter(res.headers, body);
        const waitMs = Math.max(waitSec * 1000, 500 * Math.pow(2, attempt));
        onRateLimit(waitMs);
        await sleep(waitMs);
        attempt++;
        continue;
      }

      const body = await readJson(res);
      throw new HttpError(res.status, res.statusText, body);
    }
  }

  async function complete(request) {
    if (!request || !Array.isArray(request.messages)) {
      throw new TypeError('complete: request.messages is required');
    }
    const res = await safeFetch('/chat/completions', {
      method: 'POST',
      body: JSON.stringify({ ...request, stream: false }),
    });
    const json = await res.json();
    if (json.usage) onUsage(json.usage);
    return json;
  }

  async function* completeStream(request) {
    if (!request || !Array.isArray(request.messages)) {
      throw new TypeError('completeStream: request.messages is required');
    }
    const res = await safeFetch('/chat/completions', {
      method: 'POST',
      body: JSON.stringify({ ...request, stream: true }),
    });

    if (!res.body) throw new Error('completeStream: response has no body');

    const reader = res.body.getReader();
    const decoder = new TextDecoder();
    let buf = '';
    let usageFired = false;
    const fireUsageOnce = (u) => {
      if (u && !usageFired) {
        usageFired = true;
        onUsage(u);
      }
    };

    while (true) {
      const { done, value } = await reader.read();
      if (done) break;
      buf += decoder.decode(value, { stream: true });

      let idx;
      while ((idx = buf.indexOf('\n')) !== -1) {
        const line = buf.slice(0, idx).replace(/\r$/, '');
        buf = buf.slice(idx + 1);
        if (!line || line.startsWith(':')) continue;
        if (!line.startsWith('data:')) continue;
        const data = line.slice(5).trim();
        if (data === '[DONE]') return;
        try {
          const chunk = JSON.parse(data);
          fireUsageOnce(chunk.usage);
          yield chunk;
        } catch {
          // ignore malformed line
        }
      }
    }
  }

  async function listModels() {
    const res = await safeFetch('/models', { method: 'GET' });
    return res.json();
  }

  return { complete, completeStream, listModels };
}

// ====== llm/extractor.mjs ======
/**
 * One-shot Claude Code headless call. Each run spawns a fresh subprocess,
 * does the work, exits. Suitable for batch/extraction work with no tools.
 */

const DEFAULT_SYSTEM_PROMPT =
  'You are a structured data extractor. You always respond with JSON matching the schema described in the user\'s prompt. Never include markdown fences, prose, or explanation — JSON only.';

async function* singlePrompt(text) {
  yield {
    type: 'user',
    message: { role: 'user', content: text },
    parent_tool_use_id: null,
  };
}

/**
 * @param {object} opts
 * @param {string} opts.prompt
 * @param {string} [opts.systemPrompt]
 * @param {string} [opts.model]
 * @param {Function} [opts.spawnClaudeCodeProcess]
 * @returns {Promise<{ result: string, isError: boolean, wallMs: number }>}
 */
async function runOneShotExtractor({
  prompt,
  systemPrompt = DEFAULT_SYSTEM_PROMPT,
  model,
  spawnClaudeCodeProcess,
}) {
  const t0 = Date.now();
  const q = query({
    prompt: singlePrompt(prompt),
    options: {
      model: model ?? process.env.AGENT_MODEL ?? 'claude-opus-4-7',
      settingSources: [],
      persistSession: false,
      tools: [],
      allowedTools: [],
      strictMcpConfig: true,
      mcpServers: {},
      ...(spawnClaudeCodeProcess ? { spawnClaudeCodeProcess } : {}),
      systemPrompt,
    },
  });
  for await (const msg of q) {
    if (msg.type === 'result') {
      return { result: msg.result ?? '', isError: msg.is_error ?? false, wallMs: Date.now() - t0 };
    }
  }
  throw new Error('extractor exited without a result');
}

// ====== llm/persistent-query.mjs ======
/**
 * Persistent Claude Code headless session. Push prompts in, get results out.
 * One subprocess stays warm across many turns. Ported from the elsa2 pattern.
 */

class PushIterable {
  constructor() {
    this.queue = [];
    this.resolvers = [];
    this.ended = false;
  }
  push(item) {
    if (this.ended) throw new Error('push after end');
    if (this.resolvers.length) this.resolvers.shift()({ value: item, done: false });
    else this.queue.push(item);
  }
  end() {
    this.ended = true;
    while (this.resolvers.length) this.resolvers.shift()({ value: undefined, done: true });
  }
  [Symbol.asyncIterator]() {
    return {
      next: () => {
        if (this.queue.length) return Promise.resolve({ value: this.queue.shift(), done: false });
        if (this.ended) return Promise.resolve({ value: undefined, done: true });
        return new Promise((resolve) => this.resolvers.push(resolve));
      },
    };
  }
}

function createPersistentQuery(options) {
  const input = new PushIterable();
  const q = query({ prompt: input, options });

  let pending = null;
  let sessionId = null;
  let readerDone = null;

  const reader = (async () => {
    try {
      for await (const msg of q) {
        if (msg.type === 'system' && msg.subtype === 'init') sessionId = msg.session_id;
        if (msg.type === 'result' && pending) {
          const { resolve } = pending;
          pending = null;
          resolve(msg);
        }
      }
    } finally {
      if (readerDone) readerDone();
    }
  })();

  let inFlight = Promise.resolve();

  async function runOne(prompt) {
    const t0 = Date.now();
    const result = await new Promise((resolve, reject) => {
      pending = { resolve, reject };
      input.push({
        type: 'user',
        message: { role: 'user', content: prompt },
        parent_tool_use_id: null,
      });
    });
    return {
      result: result.result,
      isError: result.is_error ?? false,
      wallMs: Date.now() - t0,
      sdkMs: result.duration_ms,
      apiMs: result.duration_api_ms,
      numTurns: result.num_turns,
      sessionId: result.session_id ?? sessionId,
    };
  }

  function run(prompt) {
    const next = inFlight.then(() => runOne(prompt));
    inFlight = next.catch(() => {});
    return next;
  }

  async function close() {
    input.end();
    await new Promise((resolve) => { readerDone = resolve; setTimeout(resolve, 5000); });
  }

  return { run, close, get sessionId() { return sessionId; } };
}

// ====== llm/openai-adapter.mjs ======
/**
 * OpenAI Chat Completions <-> Claude Code headless adapter.
 *
 * The agent always speaks OpenAI format. In production a real openai-http
 * implementation will sit behind the same interface. In development this
 * adapter translates the OpenAI request into a Claude Code headless call,
 * runs it, and shapes the response back into an OpenAI ChatCompletion.
 *
 * Scope of this file:
 *   - complete(request): non-streaming chat completion. Supports text content
 *     and a multi-turn `messages` history. Tool definitions in `request.tools`
 *     are forwarded as a text protocol in the system prompt and parsed out of
 *     the model's response when present.
 *   - createAdapter({ spawnClaudeCodeProcess }): factory if you want to
 *     supply a custom spawn (e.g. patch-fetch.mjs preload, env injection).
 *
 * Out of scope (TODO):
 *   - finish_reason=length continuation
 *   - proper token counting (estimates only)
 */

const TOOL_CALL_OPEN = '<<TOOL_CALL>>';
const TOOL_CALL_CLOSE = '<<END_TOOL_CALL>>';

function flattenContent(content) {
  if (content == null) return '';
  if (typeof content === 'string') return content;
  if (Array.isArray(content)) {
    return content
      .map((part) => {
        if (typeof part === 'string') return part;
        if (part?.type === 'text') return part.text ?? '';
        return '';
      })
      .join('');
  }
  return String(content);
}

function buildSystemPrompt(messages, tools) {
  const systemParts = messages
    .filter((m) => m.role === 'system')
    .map((m) => flattenContent(m.content))
    .filter(Boolean);

  if (tools && tools.length) {
    const toolDescriptions = tools
      .filter((t) => t.type === 'function' && t.function)
      .map((t) => {
        const f = t.function;
        return `- name: ${f.name}\n  description: ${f.description ?? ''}\n  parameters: ${JSON.stringify(f.parameters ?? {})}`;
      })
      .join('\n');
    systemParts.push(
      [
        'You may invoke any of the following tools. To call a tool, emit a single line of the form:',
        `${TOOL_CALL_OPEN}{"name":"<tool_name>","arguments":{...}}${TOOL_CALL_CLOSE}`,
        'Emit ONLY that line when calling a tool — no surrounding prose. If you do not need a tool, answer normally.',
        '',
        'Available tools:',
        toolDescriptions,
      ].join('\n'),
    );
  }

  return systemParts.join('\n\n');
}

function buildConversationPrompt(messages) {
  const turns = messages.filter((m) => m.role !== 'system');
  if (turns.length === 0) return '';
  // Single user turn: pass straight through.
  if (turns.length === 1 && turns[0].role === 'user') {
    return flattenContent(turns[0].content);
  }
  // Multi-turn: serialise with role labels so Claude has the history.
  const lines = [];
  for (const m of turns) {
    if (m.role === 'user') {
      lines.push(`User: ${flattenContent(m.content)}`);
    } else if (m.role === 'assistant') {
      const text = flattenContent(m.content);
      if (text) lines.push(`Assistant: ${text}`);
      if (Array.isArray(m.tool_calls)) {
        for (const tc of m.tool_calls) {
          lines.push(
            `Assistant called tool ${tc.function?.name} with arguments ${tc.function?.arguments ?? '{}'} (id=${tc.id}).`,
          );
        }
      }
    } else if (m.role === 'tool') {
      lines.push(
        `Tool result (id=${m.tool_call_id ?? '?'}): ${flattenContent(m.content)}`,
      );
    }
  }
  lines.push('Assistant:');
  return lines.join('\n\n');
}

function parseToolCall(text) {
  if (typeof text !== 'string') return null;
  const open = text.indexOf(TOOL_CALL_OPEN);
  if (open === -1) return null;
  const close = text.indexOf(TOOL_CALL_CLOSE, open + TOOL_CALL_OPEN.length);
  if (close === -1) return null;
  const payload = text.slice(open + TOOL_CALL_OPEN.length, close).trim();
  try {
    const parsed = JSON.parse(payload);
    if (!parsed?.name) return null;
    return {
      id: `call_${randomUUID().replace(/-/g, '').slice(0, 24)}`,
      type: 'function',
      function: {
        name: parsed.name,
        arguments: JSON.stringify(parsed.arguments ?? {}),
      },
    };
  } catch {
    return null;
  }
}

function estimateTokens(text) {
  if (!text) return 0;
  // Rough char-based estimate. Replace with proper tokenizer if needed.
  return Math.ceil(text.length / 4);
}

function shapeResponse({ extractorResult, model, promptText, systemText }) {
  const content = extractorResult.result ?? '';
  const toolCall = parseToolCall(content);

  const message = toolCall
    ? { role: 'assistant', content: null, tool_calls: [toolCall] }
    : { role: 'assistant', content };

  const finishReason = toolCall ? 'tool_calls' : 'stop';
  const promptTokens = estimateTokens(promptText) + estimateTokens(systemText);
  const completionTokens = estimateTokens(content);

  return {
    id: `chatcmpl-${randomUUID().replace(/-/g, '').slice(0, 24)}`,
    object: 'chat.completion',
    created: Math.floor(Date.now() / 1000),
    model: model ?? 'claude-code-headless',
    choices: [{ index: 0, message, finish_reason: finishReason, logprobs: null }],
    usage: {
      prompt_tokens: promptTokens,
      completion_tokens: completionTokens,
      total_tokens: promptTokens + completionTokens,
    },
    _meta: {
      wallMs: extractorResult.wallMs,
      isError: extractorResult.isError,
      via: 'claude-code-headless',
    },
  };
}

function createAdapter({ spawnClaudeCodeProcess } = {}) {
  async function complete(request) {
    if (!request || !Array.isArray(request.messages)) {
      throw new TypeError('complete: request.messages is required');
    }
    if (request.stream) {
      throw new Error('complete: streaming not yet implemented; use completeStream() (TODO)');
    }

    const systemText = buildSystemPrompt(request.messages, request.tools);
    const promptText = buildConversationPrompt(request.messages);

    const extractorResult = await runOneShotExtractor({
      prompt: promptText,
      systemPrompt: systemText || undefined,
      model: process.env.AGENT_MODEL,
      spawnClaudeCodeProcess,
    });

    return shapeResponse({ extractorResult, model: request.model, promptText, systemText });
  }

  async function* completeStream(request) {
    if (!request || !Array.isArray(request.messages)) {
      throw new TypeError('completeStream: request.messages is required');
    }
    const systemText = buildSystemPrompt(request.messages, request.tools);
    const promptText = buildConversationPrompt(request.messages);

    const id = `chatcmpl-${randomUUID().replace(/-/g, '').slice(0, 24)}`;
    const created = Math.floor(Date.now() / 1000);
    const model = request.model ?? 'claude-code-headless';
    const hasTools = Array.isArray(request.tools) && request.tools.length > 0;

    function chunk(delta, finish_reason = null) {
      return {
        id,
        object: 'chat.completion.chunk',
        created,
        model,
        choices: [{ index: 0, delta, finish_reason, logprobs: null }],
      };
    }

    yield chunk({ role: 'assistant' });

    const q = query({
      prompt: (async function* () {
        yield { type: 'user', message: { role: 'user', content: promptText }, parent_tool_use_id: null };
      })(),
      options: {
        model: process.env.AGENT_MODEL ?? 'claude-opus-4-7',
        settingSources: [],
        persistSession: false,
        tools: [],
        allowedTools: [],
        strictMcpConfig: true,
        mcpServers: {},
        includePartialMessages: true,
        ...(spawnClaudeCodeProcess ? { spawnClaudeCodeProcess } : {}),
        ...(systemText ? { systemPrompt: systemText } : {}),
      },
    });

    // Tool calls in dev mode are delivered via the <<TOOL_CALL>>{...}<<END>>
    // envelope embedded in the text stream. If the caller passed tools, we
    // buffer the entire text and decide tool-call vs. content at the end.
    // Without tools, we pass text deltas straight through.
    let buffered = '';
    let finalText = null;
    let finishReason = 'stop';

    for await (const msg of q) {
      if (msg.type === 'stream_event' && msg.event?.type === 'content_block_delta') {
        const delta = msg.event.delta;
        if (delta?.type === 'text_delta' && typeof delta.text === 'string') {
          if (hasTools) {
            buffered += delta.text;
          } else {
            yield chunk({ content: delta.text });
          }
        }
      }
      if (msg.type === 'result') {
        finalText = msg.result ?? buffered;
        break;
      }
    }

    if (hasTools) {
      const toolCall = parseToolCall(finalText ?? buffered);
      if (toolCall) {
        finishReason = 'tool_calls';
        yield chunk({
          tool_calls: [
            {
              index: 0,
              id: toolCall.id,
              type: 'function',
              function: { name: toolCall.function.name, arguments: toolCall.function.arguments },
            },
          ],
        });
      } else {
        const text = finalText ?? buffered;
        if (text) yield chunk({ content: text });
      }
    }

    yield chunk({}, finishReason);
  }

  return { complete, completeStream };
}

const defaultAdapter = createAdapter();



// ====== main ======
async function __main() {
  const question = process.argv.slice(2).join(' ').trim()
    || 'What is the capital of Japan?';
  const useStream = process.env.AGENT_STREAM === '1';

  let adapter;
  if (LLM_MODE === 'openai-http') {
    adapter = createHttpAdapter({
      baseURL: BASE_URL,
      apiKey: API_KEY,
      onUnlock: (url) => console.error(`[unlock] hit ${url}`),
      onRateLimit: (ms) => console.error(`[rate-limit] sleeping ${ms}ms`),
      onUsage: (u) => console.error(`[usage] ${JSON.stringify(u)}`),
    });
  } else if (LLM_MODE === 'claude-code-headless') {
    ({ query } = await import('@anthropic-ai/claude-agent-sdk'));
    adapter = createAdapter();
  } else {
    throw new Error(`unknown LLM_MODE: ${LLM_MODE}`);
  }

  console.error(`[mode=${LLM_MODE} stream=${useStream}] Q: ${question}`);
  const request = {
    model: MODEL,
    messages: [
      { role: 'system', content: 'Answer concisely.' },
      { role: 'user', content: question },
    ],
  };

  const t0 = Date.now();
  if (useStream) {
    let finish = null;
    for await (const chunk of adapter.completeStream(request)) {
      const d = chunk.choices?.[0]?.delta ?? {};
      if (d.content) process.stdout.write(d.content);
      if (chunk.choices?.[0]?.finish_reason) finish = chunk.choices[0].finish_reason;
    }
    process.stdout.write('\n');
    console.error(`[done] wallMs=${Date.now() - t0} finish=${finish}`);
  } else {
    const res = await adapter.complete(request);
    const content = res.choices?.[0]?.message?.content ?? '';
    process.stdout.write(content + '\n');
    console.error(`[done] wallMs=${Date.now() - t0} finish=${res.choices?.[0]?.finish_reason} usage=${JSON.stringify(res.usage ?? {})}`);
  }
}

__main().catch((e) => { console.error('FAIL:', e); process.exit(1); });
